import React, { useState, useEffect, useRef } from 'react';
import logo from './logo.svg';
import './App.css';

function App() {
  const [displayText, setDisplayText] = useState('');
  const terminalRef = useRef(null);

  useEffect(() => {
    const terminalOutputs = [
      'Initializing...',
      'Loading components...',
      'Running scripts...',
      'Process complete!',
    ];

    let currentIndex = 0;

    const typeTerminalOutput = () => {
      if (currentIndex < terminalOutputs.length) {
        setDisplayText((prevText) => prevText + terminalOutputs[currentIndex] + '\n');
        currentIndex++;

        terminalRef.current.scrollTop = terminalRef.current.scrollHeight;

        setTimeout(typeTerminalOutput, 1500);
      } else {
        setTimeout(() => {
          setDisplayText((prevText) => prevText + 'My name is Nathaniel\n');
          setTimeout(() => {
            setDisplayText((prevText) => prevText.replace('My name is Nathaniel', 'My name is Nathaniel\n'));
            setTimeout(() => {
              setDisplayText((prevText) => prevText.replace('My name is Nathaniel\n', 'My name is Nathaniel\nBut people call me Nate\n'));
            }, 2000);
          }, 3000);
        }, 3000);
      }
    };

    typeTerminalOutput();
  }, []);

  return (
    <div className="App">
      <header className="App-header">
        <img src={logo} className="App-logo" alt="logo" />
        <div className="terminal" ref={terminalRef}>
          <pre>{displayText}</pre>
          <form>
            <span className="prompt">&gt;</span>
            <input type="text" value="My name is Nathaniel" disabled />
          </form>
        </div>
        <a className="App-link" href="https://reactjs.org" target="_blank" rel="noopener noreferrer">
          Learn React
        </a>
      </header>
    </div>
  );
}

export default App;
